public boolean inserMarkupTrans(salesline  _salesLine, ETG_PostPackingQualityGrp   _etg_PostPackingQualityGrp, boolean  _salestableMarkupTrans)
{
    LineAmount                         charges, addcharges;
    MarkupTrans                        markupTrans, markupTransloc;
    boolean                             updateStatus;
    ETGQualitySpecificationSubGroup    etgQualitySpecificationSubGroup;
    SalesTable              salestable;

    #define.Percent(100)


    if (_etg_PostPackingQualityGrp.SubGroupID)
    {
        charges = 0;
        select firstonly etgQualitySpecificationSubGroup where etgQualitySpecificationSubGroup.SubGroupID == _etg_PostPackingQualityGrp.SubGroupID;

        if (_salestableMarkupTrans)
        {
            salestable = SalesTable::find(_salesLine.SalesId);

            select * from markupTrans
                         where markupTrans.MarkupCode == etgQualitySpecificationSubGroup.SalesChargeCode
                && markupTrans.TransRecId == salestable.RecId;
        }
        else
        {
            select * from markupTrans
                         where markupTrans.MarkupCode == etgQualitySpecificationSubGroup.SalesChargeCode
                && markupTrans.TransRecId == _salesLine.RecId;
        }

        if (_etg_PostPackingQualityGrp.Increment)
        {
            charges = _salesLine.LineAmount * _etg_PostPackingQualityGrp.Increment/#Percent;
            addcharges  += charges;
        }
        if (_etg_PostPackingQualityGrp.FixedValue)
        {
            charges = _etg_PostPackingQualityGrp.FixedValue;
            addcharges  += charges;
        }

        if (markupTrans.RecId)
        {
            ttsbegin;
            markupTrans.selectForUpdate(true);
            markupTrans.Value += charges;
            markupTrans.doupdate();
            ttscommit;
        }
        else
        {
            select count(RecId) from markupTransloc where markupTransloc.TransRecId == _salesLine.RecId;

            //select count(RecId) from markupTransloc where markupTransloc.TransRecId == salestable.RecId;


            if (_salestableMarkupTrans)
            {
                select count(RecId) from markupTransloc where markupTransloc.TransRecId == salestable.RecId;
                markupTrans.TransRecId      = salestable.RecId;
                markupTrans.TransTableId    = salestable.TableId;
                markupTrans.Value           = charges;
                markupTrans.LineNum         = markupTransloc.recid + 1;
            }
            else
            {
                markupTrans.TransRecId      = _salesLine.RecId;
                markupTrans.TransTableId    = _salesLine.TableId;
                markupTrans.Value           = charges;
                markupTrans.LineNum         = markupTransloc.recid + 1;
            }

            markupTrans.MarkupCode      = etgQualitySpecificationSubGroup.SalesChargeCode;
            markupTrans.Txt             = etgQualitySpecificationSubGroup.SubGroupDescription;
            markupTrans.ModuleCategory  = HeadingLine::Line;
            markupTrans.ModuleType      = MarkupModuleType::Cust;
            markupTrans.MCROriginalMiscChargeValue  = markupTrans.Value;
            markupTrans.doInsert();
        }
        markupTrans.clear();
    }

    if (!_etg_PostPackingQualityGrp.ResultValue)
    {
        updateStatus = false;
    }

    if (_salesLine.RecId && addcharges)
    {
        ttsbegin;
        _salesLine.selectForUpdate(true);
        _salesLine.LineAmount += addcharges;
        _salesLine.doUpdate();
        ttscommit;
        addcharges = 0;
    }

    return updateStatus;
}
